hooks.command:
echo "$CLAUDE_TOOL_INPUT" | python3 -c "
import sys, re, os, json
cmd = sys.stdin.read()
if 'git commit' not in cmd:
    sys.exit(0)
task_id = ''
if os.path.exists('task.md'):
    m = re.search(r'^Task:\s+(\S+)', open('task.md').read(), re.MULTILINE)
    if m:
        task_id = m.group(1)
if task_id:
    print(json.dumps({'systemMessage': f'Active task: {task_id}. Prefix this commit message with the task ID — format: \"{task_id} - <what changed and why>\".'}))
else:
    print(json.dumps({'systemMessage': 'No active task ID found in task.md. Use format: \"<type> - <what changed and why>\" (e.g. fix - ..., chore - ..., feat - ...).'}))
" 2>/dev/null || true
